"""
Texturas de papel embutidas como base64.
Geradas automaticamente — não editar manualmente.
"""
import base64, tempfile
from pathlib import Path

_DAY_B64   = ""
_NIGHT_B64 = ""

_cache = {}

def get_texture_path(mode: str) -> str:
    """Retorna caminho para PNG temporário da textura (mode='day'|'night')."""
    if mode in _cache:
        return _cache[mode]
    data = base64.b64decode(_DAY_B64 if mode == "day" else _NIGHT_B64)
    tmp = Path(tempfile.gettempdir()) / f"cronos_paper_{mode}.png"
    tmp.write_bytes(data)
    _cache[mode] = str(tmp).replace("\\", "/")
    return _cache[mode]
